+    fn stats_clear_oldest_lag_when_queue_is_drained() {
+        run_async_test(async {
+            let bus = EventBus::new(4);
+            let mut delta_sub = bus.subscribe_deltas();
+
+            let _ = bus.publish(Event::SegmentCaptured {
+                pane_id: 1,
+                seq: 0,
+                content_len: 1,
+            });
