+                pane_id: 1,
+                seq: 1,
+                content_len: 1,
+            });
+
+            delta_sub.recv().await.unwrap();
+            delta_sub.recv().await.unwrap();
+
+            let stats = bus.stats();
+            assert_eq!(stats.delta_queued, 0);
+            assert_eq!(stats.delta_oldest_lag_ms, None);
+        });
